CREATE TABLE animal (id INT AUTO_INCREMENT NOT NULL, nom VARCHAR(255) NOT NULL, espece VARCHAR(255) NOT NULL, race VARCHAR(255) DEFAULT NULL, poids DOUBLE PRECISION DEFAULT NULL, etatSante VARCHAR(255) DEFAULT NULL, userId INT DEFAULT NULL, date_naissance DATE DEFAULT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE animal_nourriture (id INT AUTO_INCREMENT NOT NULL, quantity_fed DOUBLE PRECISION NOT NULL, feeding_date DATETIME DEFAULT NULL, notes VARCHAR(255) DEFAULT NULL, animal_id INT DEFAULT NULL, nourriture_id INT DEFAULT NULL, INDEX IDX_A9B23EF78E962C16 (animal_id), INDEX IDX_A9B23EF798BD5834 (nourriture_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE carts (id INT AUTO_INCREMENT NOT NULL, buyer_id INT DEFAULT NULL, INDEX IDX_4E004AAC6C755722 (buyer_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE cart_items (id INT AUTO_INCREMENT NOT NULL, quantity INT NOT NULL, cart_id INT NOT NULL, product_id INT NOT NULL, INDEX IDX_BEF484451AD5CDBF (cart_id), INDEX IDX_BEF484454584665A (product_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE culture (id_culture INT AUTO_INCREMENT NOT NULL, nom VARCHAR(255) NOT NULL, type_culture VARCHAR(255) DEFAULT NULL, date_plantation DATE DEFAULT NULL, date_recolte_prevue DATE DEFAULT NULL, etat_culture VARCHAR(255) DEFAULT NULL, info_file_name VARCHAR(255) DEFAULT NULL, updated_at DATETIME DEFAULT NULL, parcelle_id INT DEFAULT NULL, INDEX IDX_B6A99CEB4433ED66 (parcelle_id), PRIMARY KEY(id_culture)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE email_otp (id INT AUTO_INCREMENT NOT NULL, email VARCHAR(100) NOT NULL, code VARCHAR(10) NOT NULL, expiry DATETIME NOT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE equipement (id INT AUTO_INCREMENT NOT NULL, nom VARCHAR(255) DEFAULT NULL, type VARCHAR(255) DEFAULT NULL, prix DOUBLE PRECISION DEFAULT NULL, disponibilite VARCHAR(255) DEFAULT NULL, user_id INT DEFAULT NULL, INDEX IDX_B8B4C6F3A76ED395 (user_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE equipement_geo (garage_id INT DEFAULT NULL, position_gps VARCHAR(50) DEFAULT NULL, statut_garage VARCHAR(20) DEFAULT 'DANS_GARAGE', derniere_localisation DATETIME DEFAULT NULL, equipement_id INT NOT NULL, PRIMARY KEY(equipement_id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE garage (id INT AUTO_INCREMENT NOT NULL, nom VARCHAR(255) NOT NULL, adresse VARCHAR(255) DEFAULT NULL, latitude DOUBLE PRECISION DEFAULT NULL, longitude DOUBLE PRECISION DEFAULT NULL, capacite INT DEFAULT NULL, responsable VARCHAR(255) DEFAULT NULL, telephone VARCHAR(255) DEFAULT NULL, date_creation DATETIME NOT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE garage_equipement (garage_id INT NOT NULL, equipement_id INT NOT NULL, INDEX IDX_C1B083F5C4FFF555 (garage_id), INDEX IDX_C1B083F5806F0F5C (equipement_id), PRIMARY KEY(garage_id, equipement_id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE messenger_messages (id INT AUTO_INCREMENT NOT NULL, body LONGTEXT NOT NULL, headers LONGTEXT NOT NULL, queue_name VARCHAR(255) NOT NULL, created_at DATETIME NOT NULL, available_at DATETIME NOT NULL, delivered_at DATETIME DEFAULT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE nourriture (id INT AUTO_INCREMENT NOT NULL, name VARCHAR(255) NOT NULL, type VARCHAR(255) NOT NULL, quantity DOUBLE PRECISION NOT NULL, unit VARCHAR(255) DEFAULT NULL, nutritional_value VARCHAR(255) DEFAULT NULL, expiry_date DATETIME DEFAULT NULL, supplier VARCHAR(255) DEFAULT NULL, cost DOUBLE PRECISION DEFAULT NULL, date_added DATETIME DEFAULT NULL, is_active TINYINT(1) NOT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE `order` (id INT AUTO_INCREMENT NOT NULL, user_id INT NOT NULL, total_amount DOUBLE PRECISION NOT NULL, status VARCHAR(255) DEFAULT NULL, order_date DATETIME NOT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE order_item (id INT AUTO_INCREMENT NOT NULL, order_id INT NOT NULL, product_id INT NOT NULL, quantity DOUBLE PRECISION NOT NULL, price_at_purchase DOUBLE PRECISION NOT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE parcelle (id_parcelle INT AUTO_INCREMENT NOT NULL, nom VARCHAR(255) NOT NULL, superficie DOUBLE PRECISION NOT NULL, localisation VARCHAR(255) DEFAULT NULL, type_sol VARCHAR(255) DEFAULT NULL, latitude DOUBLE PRECISION DEFAULT NULL, longitude DOUBLE PRECISION DEFAULT NULL, utilisateur_id INT DEFAULT NULL, INDEX IDX_C56E2CF6FB88E14F (utilisateur_id), PRIMARY KEY(id_parcelle)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE password_reset (id INT AUTO_INCREMENT NOT NULL, email VARCHAR(255) NOT NULL, code INT NOT NULL, expiry DATETIME NOT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE products (id INT AUTO_INCREMENT NOT NULL, name VARCHAR(255) NOT NULL, description LONGTEXT DEFAULT NULL, price DOUBLE PRECISION NOT NULL, quantity INT NOT NULL, image VARCHAR(255) DEFAULT NULL, category VARCHAR(255) NOT NULL, supplier VARCHAR(255) DEFAULT NULL, expiry_date DATE DEFAULT NULL, seller_id INT DEFAULT NULL, INDEX IDX_B3BA5A5A8DE820D9 (seller_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE product_bundles (id INT AUTO_INCREMENT NOT NULL, name VARCHAR(255) NOT NULL, description LONGTEXT DEFAULT NULL, original_price DOUBLE PRECISION NOT NULL, bundle_price DOUBLE PRECISION NOT NULL, discount_percentage DOUBLE PRECISION NOT NULL, is_active TINYINT(1) NOT NULL, created_at DATETIME NOT NULL, PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE bundle_products (bundle_id INT NOT NULL, product_id INT NOT NULL, INDEX IDX_9A956B7BF1FAD9D3 (bundle_id), INDEX IDX_9A956B7B4584665A (product_id), PRIMARY KEY(bundle_id, product_id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE ratings (id INT AUTO_INCREMENT NOT NULL, user_id INT DEFAULT NULL, rating INT NOT NULL, comment LONGTEXT DEFAULT NULL, price_category VARCHAR(255) DEFAULT NULL, created_at DATETIME NOT NULL, product_id INT DEFAULT NULL, INDEX IDX_CEB607C94584665A (product_id), INDEX IDX_CEB607C9A76ED395 (user_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE rating_likes (id INT AUTO_INCREMENT NOT NULL, is_like TINYINT(1) NOT NULL, rating_id INT NOT NULL, user_id INT NOT NULL, INDEX IDX_D4DC4141A32EFC6 (rating_id), INDEX IDX_D4DC4141A76ED395 (user_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE review (id INT AUTO_INCREMENT NOT NULL, commentaire LONGTEXT DEFAULT NULL, note INT DEFAULT NULL, date_review DATE DEFAULT NULL, equipement_id INT DEFAULT NULL, user_id INT DEFAULT NULL, INDEX IDX_794381C6806F0F5C (equipement_id), INDEX IDX_794381C6A76ED395 (user_id), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE user_otp (user_id INT AUTO_INCREMENT NOT NULL, otp_code VARCHAR(255) NOT NULL, expires_at DATETIME NOT NULL, attempts INT DEFAULT NULL, PRIMARY KEY(user_id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
CREATE TABLE `user` (id INT AUTO_INCREMENT NOT NULL, full_name VARCHAR(100) NOT NULL, email VARCHAR(150) NOT NULL, phone VARCHAR(20) DEFAULT NULL, password_hash VARCHAR(255) NOT NULL, role VARCHAR(255) NOT NULL, created_at DATETIME DEFAULT NULL, face_descriptor JSON DEFAULT NULL, UNIQUE INDEX UNIQ_8D93D649E7927C74 (email), PRIMARY KEY(id)) DEFAULT CHARACTER SET utf8mb4 COLLATE `utf8mb4_unicode_ci`;
